testCases.expectedOutput:
BoundedContext OrderContext {
    Aggregate Order {
        orderId: UUID @identity
        customerName: String @required
        totalAmount: Decimal @min(0)
        status: String
        createdAt: DateTime
    }
}

BoundedContext OrderContext {
    Aggregate Order {
        orderId: UUID @identity
        customerName: String @required
        items: List<OrderItem>
        totalAmount: Decimal
        status: String

        operations {
            when placing order with customer and items:
                require that customer is not empty and items is not empty
                calculate total as sum of items price
                set status to "PENDING"
                emit OrderPlaced with orderId
        }
    }
}

BoundedContext OrderContext {
    Aggregate Order {
        orderId: UUID @identity
        customerName: String @required
        status: String @default("PENDING")
        createdAt: DateTime
        expiresAt: DateTime

        state machine for status {
            states:
                - PENDING (initial)
                - CONFIRMED
                - DELIVERED (final)
                - CANCELLED (final)

            transitions:
                - PENDING -> CONFIRMED: when payment received
                - CONFIRMED -> DELIVERED: always
                - [PENDING, CONFIRMED] -> CANCELLED: always
        }

        operations {
            when confirming order:
                require that status is "PENDING" and createdAt is more than 24 hours ago and payment is received
                set status to "CONFIRMED"
                emit OrderConfirmed with orderId
        }
    }
}
